import{_ as i,o as t,c as a,ag as e}from"./chunks/framework.BZohXCq9.js";const d=JSON.parse('{"title":"Sprint 2: Quản trị nội dung & Điểm đến (Implementation)","description":"","frontmatter":{},"headers":[],"relativePath":"05-quan-ly-sprint/sprint-2-quan-tri-diem-den/01-yeu-cau-nghiep-vu.md","filePath":"05-quan-ly-sprint/sprint-2-quan-tri-diem-den/01-yeu-cau-nghiep-vu.md"}'),o={name:"05-quan-ly-sprint/sprint-2-quan-tri-diem-den/01-yeu-cau-nghiep-vu.md"};function h(r,n,c,l,s,u){return t(),a("div",null,[...n[0]||(n[0]=[e('<h1 id="sprint-2-quan-tri-noi-dung-điem-đen-implementation" tabindex="-1">Sprint 2: Quản trị nội dung &amp; Điểm đến (Implementation) <a class="header-anchor" href="#sprint-2-quan-tri-noi-dung-điem-đen-implementation" aria-label="Permalink to &quot;Sprint 2: Quản trị nội dung &amp; Điểm đến (Implementation)&quot;">​</a></h1><p>Sprint này thực hiện việc hiện thực hóa các tính năng cốt lõi của CMS để chuẩn bị dữ liệu cho toàn hệ thống.</p><h2 id="_1-pham-vi-lien-ket-nghiep-vu" tabindex="-1">1. Phạm vi &amp; Liên kết nghiệp vụ <a class="header-anchor" href="#_1-pham-vi-lien-ket-nghiep-vu" aria-label="Permalink to &quot;1. Phạm vi &amp; Liên kết nghiệp vụ&quot;">​</a></h2><p>Các tính năng triển khai trong Sprint này được đặc tả chi tiết tại Product Backlog:</p><ul><li><a href="./../../03-kho-tinh-nang/quan-tri-noi-dung/admin-features">Hành vi Admin: Quản lý Điểm đến &amp; Tour</a></li><li><a href="./../../03-kho-tinh-nang/quan-tri-noi-dung/client-app-display">Hành vi Client: Hiển thị Nội dung</a></li></ul><h2 id="_2-acceptance-criteria-ac-tieu-chi-nghiem-thu" tabindex="-1">2. Acceptance Criteria (AC) - Tiêu chí nghiệm thu <a class="header-anchor" href="#_2-acceptance-criteria-ac-tieu-chi-nghiem-thu" aria-label="Permalink to &quot;2. Acceptance Criteria (AC) - Tiêu chí nghiệm thu&quot;">​</a></h2><h3 id="task-2-1-danh-muc-vung-mien-co-đinh-—-updated-17-05-2026" tabindex="-1">Task 2.1: Danh mục vùng miền (cố định) — [UPDATED 17/05/2026] <a class="header-anchor" href="#task-2-1-danh-muc-vung-mien-co-đinh-—-updated-17-05-2026" aria-label="Permalink to &quot;Task 2.1: Danh mục vùng miền (cố định) — [UPDATED 17/05/2026]&quot;">​</a></h3><blockquote><p><strong>Quyết định sản phẩm:</strong> Chỉ <strong>3 vùng miền</strong> (Miền Bắc, Miền Trung, Miền Nam). Không CRUD admin.</p></blockquote><ul><li><strong>AC1</strong>: Bảng <code>regions</code> được seed sẵn (<code>mb</code> / <code>mt</code> / <code>mn</code>, slug <code>mien-bac</code> | <code>mien-trung</code> | <code>mien-nam</code>).</li><li><strong>AC2</strong>: Admin chọn vùng miền bắt buộc khi tạo/sửa điểm đến (dropdown).</li><li><strong>AC3</strong>: Client và API lọc điểm đến theo <code>regionId</code> hoặc slug vùng.</li><li><s>AC cũ (CRUD thêm miền)</s> — <strong>không áp dụng</strong>.</li></ul><h3 id="task-2-2-quan-ly-điem-đen-poi" tabindex="-1">Task 2.2: Quản lý Điểm đến (POI) <a class="header-anchor" href="#task-2-2-quan-ly-điem-đen-poi" aria-label="Permalink to &quot;Task 2.2: Quản lý Điểm đến (POI)&quot;">​</a></h3><ul><li><strong>AC1</strong>: Upload ảnh lên Cloudinary thành công và lưu URL vào DB.</li><li><strong>AC2</strong>: Form validation: Tên điểm đến &gt; 5 ký tự, Slug tự động tạo và không dấu.</li><li><strong>AC3</strong>: Xóa điểm đến phải có confirm modal và check ràng buộc dữ liệu.</li></ul><h3 id="task-2-3-tich-hop-api-v1" tabindex="-1">Task 2.3: Tích hợp API v1 <a class="header-anchor" href="#task-2-3-tich-hop-api-v1" aria-label="Permalink to &quot;Task 2.3: Tích hợp API v1&quot;">​</a></h3><ul><li><strong>AC1</strong>: Toàn bộ dữ liệu được fetch thông qua Server Actions / API Routes đã thiết kế.</li><li><strong>AC2</strong>: Handle lỗi 404, 500 với giao diện Toast thông báo cho Admin.</li></ul><h3 id="task-2-4-trang-cai-đat-he-thong-system-settings" tabindex="-1">Task 2.4: Trang Cài đặt Hệ thống (System Settings) <a class="header-anchor" href="#task-2-4-trang-cai-đat-he-thong-system-settings" aria-label="Permalink to &quot;Task 2.4: Trang Cài đặt Hệ thống (System Settings)&quot;">​</a></h3><ul><li><strong>AC1</strong>: Admin có thể cấu hình thông tin chung (Logo, liên hệ), Hero Section, Stats và SEO.</li><li><strong>AC2</strong>: Dữ liệu cài đặt được lưu trữ theo dạng key-value vào bảng <code>SystemSetting</code>.</li><li><strong>AC3</strong>: Mọi thay đổi ở form được lưu bằng Server Actions và phản ánh ngay ngoài frontend (Client).</li></ul><hr><p><em>Ghi chú: Lịch trình chi tiết và Task phân rã nằm trong <a href="./../backlog-chi-tiet">Backlog chi tiết</a>.</em></p>',17)])])}const m=i(o,[["render",h]]);export{d as __pageData,m as default};
